  ('aboriginal-a5729396-moex-00024', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族教育法的規定，國民教育階段之原住民重點學校，於徵得設籍於該學區成年原住民的比例多 少以上的書面同意，始得合併或停辦學校？', '["二分之一", "三分之二", "四分之三", "五分之三"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00025', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '下列有關原住民族委員會對地方政府公共工程及公共建設型補助計畫作業及管考要點內容之敘述，何者正確？', '["該要點管考對象為各直轄市及縣（市）政府", "經核定之工程案件，受補助機關應於審議年度12月31日前完成工程設計作業，並於預算執行年度之3 月底前完成發包", "受補助機關應於工程竣工後，於4個月內完成結案作業", "受補助之工程案件原則上會在審議年度的後1年度發包執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00026', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族委員會於民國104年07月01日針對原住民族基本法第8條第2項所稱之「原住民族專責單位」 解釋令，敘明「核釋原住民族基本法第八條第二項所稱之『原住民族專責單位』，係指直轄市及縣（市）政 府之組織法規規定，以原住民或原住民族事項為其主要掌理事項之一級機關或單位……。」請問下列那一 地方政府尚未達到該解釋令敘明的標準？', '["臺南市政府", "宜蘭縣政府", "新竹市政府", "新竹縣政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00027', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族教育法的規定，請問下列何者不是原住民族教育的目的？', '["維護國家尊嚴", "延續民族命脈", "增進民族福祉", "促進族群共榮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00028', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民於原住民保留地設定之耕作權、地上權或農育權，在下列那些情況下，比較有可能依法被塗銷？', '["耕作權、地上權或農育權存續期間屆滿", "當事人死亡且無繼承人", "當事人請兄弟姊妹從事實際耕作", "當事人死亡但繼承人非原住民"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00029', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '根據原住民族語言發展法的規定，直轄市、縣（市）政府、原住民族地區及原住民人口多少人以上之非原 住民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣人員？', '["500人", "1,500人", "2,500人", "3,500人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00030', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族權利是否為一種集體權利，其學理頗多爭議。請問在下列那一解釋或判決中，大法官首次正面表 述原住民族權利為一種集體權？', '["111年憲判字第17號「西拉雅族原住民身分案」", "111年憲判字第4號「原住民與非原住民結婚所生子女之原住民身分案」", "司法院釋字第803號「原住民狩獵案」", "司法院釋字第719號「政府採購得標廠商應進用一定比例原住民案」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00031', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族教育法的規定，國家教育研究院所設的那一個單位，應負責原住民族教育相關研究之規劃及 執行、並因應各級各類學校學生學習需要，就原住民族教育政策，提供諮詢：', '["原住民族教師研究中心", "原住民族教育研究中心", "原住民族教科書研究中心", "原住民族課程發展研究中心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00032', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', 'A公司近日收到因違反原住民族工作權保障法第12條第1項，而遭到應繳納代金的行政處分。請問依據 現行之原住民族工作權保障法，下列敘述何者錯誤？', '["可確認A公司係依政府採購法得標之廠商", "可確認A公司於國內員工總人數逾3百人", "A公司應於履約期間僱用原住民，其人數不得低於總人數1%", "A公司進用原住民人數未達法定標準者，應向原住民族綜合發展基金之就業基金繳納代金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00033', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '阿美族原住民女子甲，其父為賽德克族、母為阿美族。甲與非原住民男子乙結婚所生子女，原住民身分之 民族別，依法可從之選擇，下列何者正確？', '["阿美族", "賽德克族", "由父母雙方協議從賽德克族或阿美族", "子女無法取得原住民身分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
